156→function MessageRow({ message, userName, userImage }: { message: Message; userName?: string; userImage?: string }) {
157→  const [expanded, setExpanded] = useState(false);
158→  const isHuman = message.role === "human" || message.role === "user";
159→  const toolNames = extractToolNames(message.content);
160→  const cleanContent = isHuman
161→    ? message.content
162→    : stripToolPatterns(message.content);
163→  const isLong = cleanContent.length > COLLAPSE_THRESHOLD;
164→  const displayContent =
165→    !expanded && isLong
166→      ? cleanContent.slice(0, COLLAPSE_THRESHOLD) + "..."
167→      : cleanContent;
168→
169→  return (
170→    <div className="flex gap-3 py-3">
171→      {isHuman ? <HumanAvatar userImage={userImage} /> : <AssistantAvatar />}
