175→            {isHuman ? (userName ?? "You") : "Assistant"}
176→          </span>
177→          {message.tokens != null && message.tokens > 0 && (
178→            <span className="text-xs text-muted">
179→              {message.tokens.toLocaleString()} tokens
180→            </span>
181→          )}
182→        </div>
183→        {displayContent && (
184→          <div className="whitespace-pre-wrap text-sm text-foreground/90 leading-relaxed">
185→            {displayContent}
186→          </div>
187→        )}
188→        {!isHuman && toolNames.length > 0 && (
189→          <div className="mt-2">
190→            <ToolUsagePill toolNames={toolNames} />
191→          </div>
192→        )}
193→        {isLong && (
194→          <button
195→            onClick={() => setExpanded(!expanded)}
196→            className="mt-2 text-xs text-accent-light hover:text-accent cursor-pointer"
197→          >
198→            {expanded ? "Show less" : "Show more"}
199→          </button>
200→        )}
201→      </div>
202→    </div>
203→  );
204→}
