233→function SessionAccordion({
234→  messages,
235→  agentName,
236→  agentPercent,
237→  userName,
238→  userImage,
239→}: {
240→  messages: Message[];
241→  agentName?: string;
242→  agentPercent?: number;
243→  userName?: string;
244→  userImage?: string;
245→}) {
246→  const [open, setOpen] = useState(true);
247→  const stats = computeSessionStats(messages);
248→  const grouped = groupMessages(messages);
249→
250→  return (
251→    <div className="rounded-xl border border-border bg-surface overflow-hidden">
252→      <button
253→        onClick={() => setOpen(!open)}
254→        className="flex w-full items-start justify-between gap-4 px-5 py-4 text-left cursor-pointer hover:bg-surface-light/50 transition-colors"
255→      >
256→        <div className="flex items-center gap-2 min-w-0 flex-1">
257→          <svg
258→            width="14"
259→            height="14"
260→            viewBox="0 0 24 24"
261→            fill="none"
262→            stroke="currentColor"
263→            strokeWidth="2"
264→            className={cn(
265→              "shrink-0 text-muted transition-transform",
266→              open ? "rotate-0" : "-rotate-90"
267→            )}
268→          >
269→            <polyline points="6 9 12 15 18 9" />
270→          </svg>
271→          <span className="text-sm text-foreground truncate">
272→            {stats.prompt}
273→          </span>
274→          {agentName && (
275→            <span className="shrink-0 inline-flex items-center rounded-full bg-accent-orange/15 px-2 py-0.5 text-xs font-medium text-accent-orange border border-accent-orange/30">
276→              {agentName}
277→            </span>
278→          )}
279→        </div>
280→        <div className="flex items-center gap-3 shrink-0 text-xs text-muted">
281→          {stats.startTime && <span>{stats.startTime}</span>}
282→          {stats.duration !== "—" && <span>{stats.duration}</span>}
283→          <span>{stats.steps} steps</span>
284→          {stats.toolCount > 0 && <span>{stats.toolCount} tools</span>}
285→          {stats.totalTokens > 0 && (
