 4→import { getSessionData } from "@/lib/github/session";
 5→
 6→export async function GET(
 7→  _request: Request,
 8→  { params }: { params: Promise<{ owner: string; repo: string; id: string }> }
 9→) {
10→  const session = await auth();
11→  if (!session?.accessToken) {
12→    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
13→  }
14→
15→  const { owner, repo, id } = await params;
16→  const octokit = createOctokit(session.accessToken);
17→  const messages = await getSessionData(octokit, owner, repo, id);
18→  return NextResponse.json(messages);
19→}
