 10→
 11→interface DiffFile {
 12→  header: string;
 13→  hunks: string[];
 14→}
 15→
 16→function parseDiff(raw: string): DiffFile[] {
 17→  const files: DiffFile[] = [];
 18→  const lines = raw.split("\n");
 19→  let currentFile: DiffFile | null = null;
 20→
 21→  for (const line of lines) {
 22→    if (line.startsWith("diff --git")) {
 23→      if (currentFile) files.push(currentFile);
 24→      currentFile = { header: line, hunks: [] };
 25→    } else if (currentFile) {
 26→      currentFile.hunks.push(line);
 27→    }
 28→  }
 29→
 30→  if (currentFile) files.push(currentFile);
 31→  return files;
 32→}
 33→
 34→function DiffFileBlock({ file }: { file: DiffFile }) {
 35→  const [collapsed, setCollapsed] = useState(false);
 36→
 37→  // Extract file path from header
 38→  const pathMatch = file.header.match(/b\/(.+)$/);
 39→  const filePath = pathMatch?.[1] || file.header;
 40→
 41→  const additions = file.hunks.filter((l) => l.startsWith("+") && !l.startsWith("+++")).length;
 42→  const deletions = file.hunks.filter((l) => l.startsWith("-") && !l.startsWith("---")).length;
 43→
 44→  return (
 45→    <div className="overflow-hidden rounded-lg border border-border">
 46→      <button
 47→        onClick={() => setCollapsed(!collapsed)}
 48→        className="flex w-full items-center justify-between bg-surface px-4 py-2 text-left cursor-pointer"
 49→      >
 50→        <span className="font-mono text-sm text-foreground">{filePath}</span>
 51→        <div className="flex items-center gap-2">
 52→          {additions > 0 && (
 53→            <span className="text-xs text-success">+{additions}</span>
 54→          )}
 55→          {deletions > 0 && (
 56→            <span className="text-xs text-red-400">-{deletions}</span>
 57→          )}
 58→          <svg
 59→            width="14"
 60→            height="14"
 61→            viewBox="0 0 24 24"
 62→            fill="none"
 63→            stroke="currentColor"
 64→            strokeWidth="2"
 65→            className={cn(
 66→              "text-muted transition-transform",
 67→              collapsed && "-rotate-90"
 68→            )}
 69→          >
 70→            <polyline points="6 9 12 15 18 9" />
 71→          </svg>
 72→        </div>
 73→      </button>
 74→
 75→      {!collapsed && (
 76→        <div className="overflow-x-auto bg-background">
 77→          <pre className="text-xs leading-5">
 78→            {file.hunks.map((line, idx) => {
 79→              let lineClass = "text-muted";
 80→              let bgClass = "";
 81→
 82→              if (line.startsWith("+") && !line.startsWith("+++")) {
 83→                lineClass = "text-success";
 84→                bgClass = "bg-success/10";
 85→              } else if (line.startsWith("-") && !line.startsWith("---")) {
 86→                lineClass = "text-red-400";
 87→                bgClass = "bg-red-500/10";
 88→              } else if (line.startsWith("@@")) {
 89→                lineClass = "text-accent-light";
 90→                bgClass = "bg-accent/5";
 91→              }
 92→
 93→              return (
 94→                <div
 95→                  key={idx}
 96→                  className={cn("px-4 py-0", bgClass)}
 97→                >
 98→                  <span className={lineClass}>{line}</span>
 99→                </div>
100→              );
101→            })}
102→          </pre>
103→        </div>
104→      )}
105→    </div>
106→  );
107→}
