117→
118→  const files = parseDiff(diff);
119→
120→  return (
121→    <div className={cn("space-y-3", className)}>
122→      {files.map((file, idx) => (
123→        <DiffFileBlock key={idx} file={file} />
124→      ))}
125→    </div>
126→  );
127→}
